// TOPIC 12: ESTIMATION & COSTING — Tariff & Energy Billing (16Q)
// ─────────────────────────────────────────────────────────
QUESTION_BANK[12].push(
{ q:"A 'flat rate' electricity tariff structure charges the consumer:",
  opts:["A fixed rate per unit (kWh) consumed, regardless of time of use or demand","Different rates depending only on the time of day","A rate based purely on connected load, ignoring actual consumption","No charge at all for energy consumed"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Under a flat rate tariff, every unit of energy consumed is billed at the same fixed rate, irrespective of when it was used." },
{ q:"A 'two-part' electricity tariff structure typically consists of:",
  opts:["A fixed charge (based on connected load/demand) plus a running charge based on energy consumed","Only a fixed charge, with no running (per-unit) component","Only a running charge, with no fixed component","A charge based solely on the consumer's location"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Two-part tariffs separately recover fixed infrastructure costs (via the demand charge) and variable energy costs (via the per-unit running charge)." },
{ q:"The fixed (demand) charge component in a two-part tariff is primarily meant to:",
  opts:["Recover the utility's fixed costs (like generation capacity/infrastructure) that don't vary with consumption","Discourage consumers from using any electricity at all","Charge consumers exclusively for their peak-hour usage","Replace the need for any energy meter"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since infrastructure costs exist regardless of how much energy is actually consumed, the fixed charge ensures these costs are recovered independent of usage." },
{ q:"A 'maximum demand tariff' charges the consumer partly based on:",
  opts:["The highest average power demand recorded during a billing period","Only the total energy consumed, ignoring peak demand entirely","The consumer's total connected load, regardless of actual usage","The time of day electricity was first connected"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This tariff structure reflects the fact that supplying a high peak demand requires the utility to maintain sufficient capacity, even if average consumption is much lower." },
{ q:"The 'load factor' of a consumer/system is defined as:",
  opts:["The ratio of average load (demand) to the maximum (peak) demand over a period","The ratio of maximum demand to connected load","The total energy consumed divided by the billing period only","The ratio of voltage to current at peak load"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Load factor indicates how consistently a load is used relative to its peak — a higher load factor means demand is spread more evenly rather than sharply peaked." },
{ q:"A consumer has an average load of 40 kW and a maximum demand of 100 kW. Find the load factor.",
  opts:["40%","25%","60%","400%"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Load factor = Average load/Maximum demand = 40/100 = 0.4 = 40%." },
{ q:"A higher load factor generally indicates:",
  opts:["More efficient utilisation of installed generation/distribution capacity","Very poor, sharply peaked usage of electrical capacity","No relationship to how efficiently capacity is used","Always a higher electricity bill for the consumer"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A load closer to its peak demand for more of the time (high load factor) allows generation/distribution assets to be used more effectively rather than sitting idle." },
{ q:"The 'demand factor' is defined as:",
  opts:["The ratio of maximum demand to total connected load","The ratio of total connected load to maximum demand","The ratio of average load to maximum demand","The total energy billed in a period"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Demand factor reflects what fraction of the total installed/connected load is actually realised as peak demand." },
{ q:"A consumer has a total connected load of 20 kW and a recorded maximum demand of 15 kW. Find the demand factor.",
  opts:["75%","133%","25%","20%"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Demand factor = Maximum demand/Connected load = 15/20 = 0.75 = 75%." },
{ q:"Time-of-Day (ToD) tariffs charge consumers:",
  opts:["Different rates depending on the time of day, typically higher during peak hours","The exact same rate at all hours, with no time variation","Based only on connected load, ignoring time entirely","A rate that increases with the consumer's total energy usage, regardless of time"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"By pricing peak-hour consumption higher and off-peak consumption lower, ToD tariffs encourage consumers to shift some usage away from high-demand periods." },
{ q:"A power factor penalty/incentive in commercial/industrial tariffs is applied to:",
  opts:["Encourage consumers to maintain a high power factor, penalising low power factor","Encourage consumers to use as much reactive power as possible","Charge consumers only for real power, ignoring power factor entirely","Eliminate the need for any energy metering"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Low power factor increases the reactive power burden on the supply system; tariff penalties (or rebates for high power factor) encourage consumers to correct it, often using capacitor banks." },
{ q:"A consumer's monthly bill shows 500 units (kWh) consumed, billed at ₹6 per unit under a flat rate. Find the total energy charge.",
  opts:["₹3000","₹300","₹5000","₹83.3"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Total charge = Units consumed × Rate per unit = 500 × 6 = ₹3000." },
{ q:"Installing capacitor banks at an industrial consumer's premises is primarily done to:",
  opts:["Improve power factor, reducing reactive power drawn from the supply","Increase the total real power consumed intentionally","Eliminate the need for earthing entirely","Increase the harmonic content of the supply current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Capacitor banks supply reactive power locally, reducing the reactive power the utility must supply, improving power factor and often avoiding low-power-factor penalties." },
{ q:"The 'plant capacity factor' of a power plant is defined as:",
  opts:["The ratio of actual energy generated to the maximum possible energy at full rated capacity, over the same period","The ratio of peak demand to average demand of consumers served","The total fuel consumed divided by plant lifetime","The number of generating units installed at the plant"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This factor shows how fully a plant's rated capacity is actually being utilised over time, accounting for maintenance downtime and demand variation." },
{ q:"A power plant with a rated capacity of 100 MW generates an average of 60 MW over a year. Find its plant capacity factor.",
  opts:["60%","40%","167%","100%"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Capacity factor = Average power generated/Rated capacity = 60/100 = 0.6 = 60%." },
{ q:"The main objective of a well-designed electricity tariff structure is to:",
  opts:["Ensure fair cost recovery for the utility while encouraging efficient, economical use of electricity","Maximise revenue regardless of consumer usage patterns","Charge every consumer category at exactly the same flat rate","Eliminate the need for any government regulation"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A good tariff balances the utility's need to recover costs sustainably with incentives that encourage consumers to use electricity efficiently and avoid unnecessary peak demand." }
);

