QUESTION_BANK[2].push(
{ q:"The RMS (root mean square) value of a sinusoidal AC waveform with peak value Vm is:",
  opts:["Vm/√2 (≈0.707 Vm)","Vm/2","2Vm/π","Vm×√2"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"For a pure sine wave, the RMS value equals the peak value divided by √2, roughly 70.7% of the peak." },
{ q:"The average value of a sinusoidal AC waveform (over a half cycle) with peak value Vm is:",
  opts:["2Vm/π (≈0.637 Vm)","Vm/√2","Vm/2","Vm×π"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The half-cycle average of a sine wave is 2Vm/π, roughly 63.7% of the peak value." },
{ q:"Form factor of a waveform is defined as:",
  opts:["RMS value ÷ Average value","Average value ÷ RMS value","Peak value ÷ RMS value","RMS value ÷ Peak value"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Form factor compares the RMS value to the average value, indicating the waveform's shape relative to a perfect square wave (form factor = 1)." },
{ q:"Find the form factor of a pure sinusoidal waveform.",
  opts:["≈1.11","≈1.41","≈0.707","≈1.57"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"Form factor = (Vm/√2)/(2Vm/π) = π/(2√2) ≈ 1.11 for a pure sine wave." },
{ q:"Peak factor (crest factor) of a waveform is defined as:",
  opts:["Peak value ÷ RMS value","RMS value ÷ Peak value","Average value ÷ Peak value","Peak value ÷ Average value"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Peak factor indicates how much higher the peak is compared to the RMS value of the waveform." },
{ q:"Find the peak factor of a pure sinusoidal waveform.",
  opts:["≈1.414","≈1.11","≈0.637","≈2.0"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Peak factor = Vm/(Vm/√2) = √2 ≈ 1.414 for a pure sine wave." },
{ q:"In AC circuit analysis, a phasor represents:",
  opts:["A sinusoidal quantity's magnitude and phase angle, as a rotating vector","Only the peak value of a waveform, ignoring phase","A purely DC quantity","The resistance of a circuit element only"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Phasors simplify AC analysis by representing sinusoids as complex numbers (magnitude and phase), avoiding direct time-domain differential equations." },
{ q:"The impedance of a pure resistor in an AC circuit is:",
  opts:["R (purely real, with no phase shift between voltage and current)","jωL (purely reactive)","1/(jωC) (purely reactive)","Zero, regardless of resistance value"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"A resistor's impedance has no imaginary (reactive) component, so voltage and current remain in phase across it." },
{ q:"The impedance of a pure inductor in an AC circuit is:",
  opts:["jωL, with voltage leading current by 90°","R, purely resistive","1/(jωC), with current leading voltage by 90°","Zero at all frequencies"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"An inductor's impedance is purely reactive and proportional to frequency; voltage leads current by 90° across a pure inductor." },
{ q:"The impedance of a pure capacitor in an AC circuit is:",
  opts:["1/(jωC), with current leading voltage by 90°","jωL, with voltage leading current by 90°","R, purely resistive","Infinite at all frequencies"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A capacitor's impedance is purely reactive and inversely proportional to frequency; current leads voltage by 90° across a pure capacitor." },
{ q:"In a pure inductive AC circuit, the current:",
  opts:["Lags the voltage by 90°","Leads the voltage by 90°","Is exactly in phase with the voltage","Is always zero"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"For a pure inductor, current lags voltage by a quarter cycle (90°), a classic ELI mnemonic (voltage leads current in an inductor)." },
{ q:"In a pure capacitive AC circuit, the current:",
  opts:["Leads the voltage by 90°","Lags the voltage by 90°","Is exactly in phase with the voltage","Is always zero"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"For a pure capacitor, current leads voltage by a quarter cycle (90°), the classic ICE mnemonic (current leads voltage in a capacitor)." },
{ q:"At resonance in a series RLC circuit, the net reactance (XL − XC) is:",
  opts:["Zero, so the circuit behaves purely resistively","Maximum, dominated by inductive reactance","Maximum, dominated by capacitive reactance","Undefined at resonance"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"At the resonant frequency, inductive and capacitive reactances are equal in magnitude and cancel, leaving only the resistive component." },
{ q:"The resonant frequency of a series RLC circuit is given by:",
  opts:["f0 = 1/(2π√(LC))","f0 = 2π√(LC)","f0 = 1/(2πLC)","f0 = LC/(2π)"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This standard formula gives the frequency at which inductive and capacitive reactances are equal in magnitude, cancelling each other in a series circuit." },
{ q:"Find the resonant frequency of a series RLC circuit with L = 1 H and C = 1 μF.",
  opts:["≈159.15 Hz","≈15.9 Hz","≈1591.5 Hz","≈1.59 Hz"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"f0 = 1/(2π√(LC)) = 1/(2π√(1×10⁻⁶)) = 1/(2π×10⁻³) ≈ 159.15 Hz." },
{ q:"At resonance, the impedance of a series RLC circuit is:",
  opts:["Minimum, equal to just the resistance R","Maximum, equal to R+XL+XC","Zero, regardless of R","Infinite, regardless of R"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since reactances cancel at resonance, only the pure resistance R remains, giving the minimum possible impedance for a series RLC circuit." },
{ q:"At resonance, the current in a series RLC circuit is:",
  opts:["Maximum, since impedance is at its minimum","Minimum, since impedance is at its maximum","Exactly zero","Independent of the applied voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"With minimum impedance at resonance, a series RLC circuit draws the maximum possible current for a given applied voltage." },
{ q:"The Quality factor (Q) of a series RLC circuit at resonance is given by:",
  opts:["Q = (ω0L)/R = 1/(ω0CR)","Q = R/(ω0L)","Q = ω0×R×C","Q = R×L×C"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"Q relates the energy stored in the reactive elements to the energy dissipated in the resistance per cycle, expressed via ω0L/R or its equivalent form." },
{ q:"A higher Q factor in a resonant circuit indicates:",
  opts:["A sharper, narrower resonance curve — higher selectivity and lower bandwidth","A broader, flatter resonance curve — lower selectivity","No change in bandwidth or selectivity","Higher resistive losses in the circuit"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Higher Q means lower resistive losses relative to reactance, producing a sharply peaked, highly selective resonance response." },
{ q:"The bandwidth of a series resonant circuit is related to the Q factor by:",
  opts:["BW = f0/Q","BW = f0×Q","BW = Q/f0","BW = f0 + Q"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A higher Q compresses the bandwidth relative to the resonant frequency, following BW = f0/Q." },
{ q:"A series RLC circuit has a resonant frequency of 1000 Hz and a Q factor of 50. Find its bandwidth.",
  opts:["20 Hz","50 Hz","1000 Hz","2 Hz"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"BW = f0/Q = 1000/50 = 20 Hz." },
{ q:"The 'half-power frequencies' of a resonant circuit are the frequencies at which:",
  opts:["Power delivered is half of the maximum (resonant) power","Current reaches its absolute maximum value","Impedance is exactly zero","Voltage across the resistor is at its minimum"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"At the half-power frequencies, current drops to 1/√2 of its resonant maximum, and since power ∝ I², power falls to exactly half its peak value." },
{ q:"At resonance, the impedance of a parallel RLC circuit is:",
  opts:["Maximum","Minimum","Zero","Undefined"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Unlike series resonance (minimum impedance), a parallel RLC circuit exhibits maximum impedance at its resonant frequency." },
{ q:"At resonance, the current drawn from the source by a parallel RLC circuit is:",
  opts:["Minimum","Maximum","Exactly zero","Equal to the resistive current only"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since impedance is maximum at parallel resonance, the current drawn from the source (for a given voltage) is at its minimum." },
{ q:"Parallel resonance is also commonly referred to as:",
  opts:["Anti-resonance","Sub-resonance","Over-resonance","Cross-resonance"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Because its impedance/current behaviour is opposite to series resonance, parallel resonance is often called anti-resonance." },
{ q:"'Active power' (real power) in an AC circuit is measured in:",
  opts:["Watts (W)","VAR (volt-ampere reactive)","VA (volt-amperes)","Ohms (Ω)"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Active power represents the actual power converted to useful work, measured in Watts." },
{ q:"'Reactive power' in an AC circuit is measured in:",
  opts:["VAR (volt-ampere reactive)","Watts (W)","VA (volt-amperes)","Farads (F)"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Reactive power represents energy oscillating between the source and reactive elements (L, C) without net consumption, measured in VAR." },
{ q:"'Apparent power' in an AC circuit is measured in:",
  opts:["VA (volt-amperes)","Watts (W)","VAR (volt-ampere reactive)","Joules (J)"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Apparent power is simply the product of RMS voltage and RMS current, S = VI, measured in volt-amperes." },
{ q:"The relationship between active power (P), reactive power (Q), and apparent power (S) is given by:",
  opts:["S² = P² + Q²","S = P + Q","S = P × Q","S² = P − Q"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This is the power triangle relationship, where S is the hypotenuse of a right triangle formed by P and Q." },
{ q:"Power factor of an AC circuit is defined as:",
  opts:["The cosine of the phase angle between voltage and current (P/S)","The sine of the phase angle between voltage and current","The ratio of reactive power to apparent power","Always equal to 1, regardless of load type"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Power factor = cosφ = Active power/Apparent power, indicating how effectively the supplied power is converted to useful work." },
{ q:"An AC circuit has an apparent power of 1000 VA and an active power of 800 W. Find the power factor.",
  opts:["0.8","1.25","0.2","1.0"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Power factor = P/S = 800/1000 = 0.8." },
{ q:"A power factor of 1 (unity) indicates:",
  opts:["Voltage and current are perfectly in phase, with no reactive power component","Voltage and current are 90° out of phase","The circuit contains only reactive elements","The circuit draws zero current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"At unity power factor, all supplied apparent power is active (real) power — the ideal condition for efficient power delivery." },
{ q:"A 'lagging' power factor typically occurs in circuits with predominantly:",
  opts:["Inductive loads, where current lags voltage","Capacitive loads, where current leads voltage","Purely resistive loads only","No load connected at all"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Inductive loads (like motors and transformers) cause current to lag behind voltage, producing a lagging power factor — the most common industrial scenario." }
);

// ─────────────────────────────────────────────────────────
// TOPIC 2: NETWORK THEORY — Three-Phase Circuits (35Q)
// ─────────────────────────────────────────────────────────
QUESTION_BANK[2].push(
{ q:"In a balanced three-phase system, the three phase voltages are equal in magnitude and displaced from each other by:",
  opts:["120 electrical degrees","90 electrical degrees","180 electrical degrees","60 electrical degrees"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"A balanced three-phase supply has three equal-magnitude voltages, each separated by exactly 120° in phase." },
{ q:"In a star (Y) connected three-phase system, the line voltage (VL) relates to the phase voltage (VP) as:",
  opts:["VL = √3 × VP","VL = VP","VL = 3 × VP","VL = VP/√3"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"In a star connection, line voltage is √3 times the phase (winding) voltage due to the phasor combination of two phase voltages." },
{ q:"In a star (Y) connected three-phase system, the line current (IL) relates to the phase current (IP) as:",
  opts:["IL = IP","IL = √3 × IP","IL = IP/√3","IL = 3 × IP"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"In a star connection, each line conductor directly carries the same current as its corresponding phase winding, so IL = IP." },
{ q:"In a delta (Δ) connected three-phase system, the line voltage (VL) relates to the phase voltage (VP) as:",
  opts:["VL = VP","VL = √3 × VP","VL = 3 × VP","VL = VP/3"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"In a delta connection, each line conductor connects directly across a phase winding, so line voltage equals phase voltage." },
{ q:"In a delta (Δ) connected three-phase system, the line current (IL) relates to the phase current (IP) as:",
  opts:["IL = √3 × IP","IL = IP","IL = 3 × IP","IL = IP/√3"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"In a delta connection, line current is √3 times the phase current due to the phasor combination of two phase currents at each line terminal." },
{ q:"A star-connected three-phase source has a phase voltage of 230 V. Find the line voltage.",
  opts:["≈398.4 V","230 V","≈132.8 V","690 V"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"VL = √3 × VP = √3 × 230 ≈ 398.4 V (commonly rounded to 400V supply)." },
{ q:"A delta-connected three-phase load has a phase current of 10 A. Find the line current.",
  opts:["≈17.32 A","10 A","≈5.77 A","30 A"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"IL = √3 × IP = √3 × 10 ≈ 17.32 A." },
{ q:"The total power in a balanced three-phase system (regardless of star or delta connection) is given by:",
  opts:["P = √3 × VL × IL × cosφ","P = VL × IL × cosφ","P = 3 × VL × IL","P = VL × IL / cosφ"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This standard formula, using line quantities and the load power factor, gives total three-phase power regardless of whether the load is star or delta connected." },
{ q:"A balanced three-phase system has line voltage 400 V, line current 10 A, and power factor 0.8. Find the total power.",
  opts:["≈5542.6 W","4000 W","3200 W","6928 W"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"P = √3 × VL × IL × cosφ = √3 × 400 × 10 × 0.8 ≈ 5542.6 W." },
{ q:"In a balanced three-phase star-connected system, the neutral wire carries:",
  opts:["Zero (no) current","The full line current","Three times the phase current","A current equal to the source voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since the three balanced phase currents (120° apart) sum to zero as phasors, no net current flows in the neutral under balanced conditions." },
{ q:"In an unbalanced three-phase star-connected system with a neutral wire, the neutral carries:",
  opts:["A non-zero current, equal to the phasor sum of the unbalanced phase currents","Always exactly zero current, same as the balanced case","A current equal to the largest phase current only","No current, since neutral wires only exist in balanced systems"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"When phase currents are unequal or not perfectly 120° apart, their phasor sum is non-zero, and this residual current flows through the neutral." },
{ q:"The phase sequence of a three-phase supply refers to:",
  opts:["The order in which the three phase voltages reach their positive peak values","The number of phases present in the supply","The total power delivered by the supply","The frequency of the supply voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Phase sequence (e.g., R-Y-B) describes the specific time order in which each phase voltage reaches its maximum value." },
{ q:"Reversing the phase sequence of a three-phase induction motor's supply causes the motor to:",
  opts:["Reverse its direction of rotation","Increase its speed significantly","Stop immediately and not restart","Draw zero current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The rotating magnetic field's direction depends on phase sequence; reversing any two supply phases reverses the field's rotation, and hence the motor's direction." },
{ q:"The main advantage of three-phase power transmission over single-phase, for the same power delivered, is:",
  opts:["Reduced conductor material required, with more constant (non-pulsating) power delivery","Higher voltage drop along the line","Increased total conductor weight needed","Pulsating instantaneous power delivery"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Three-phase transmission is more economical in conductor material and delivers smoother, constant instantaneous power, unlike pulsating single-phase power." },
{ q:"In a three-phase system, the instantaneous total power delivered to a balanced load is:",
  opts:["Constant (non-pulsating) over time","Pulsating at twice the supply frequency","Zero on average","Equal to the peak power at all times"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Unlike single-phase power (which pulsates), the sum of the three phase powers in a balanced three-phase system is constant at every instant." },
{ q:"A three-phase, four-wire system (with neutral) is primarily used to:",
  opts:["Supply both three-phase balanced loads and single-phase loads from the same system","Eliminate the need for any earthing","Operate only with delta-connected loads","Prevent any current from flowing in the neutral"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The neutral wire allows individual phase-to-neutral connections for single-phase loads (like household supply) alongside three-phase loads on the same system." },
{ q:"'Phase' quantities in a three-phase system refer to voltage/current measured:",
  opts:["Across or through each individual winding (phase) of the source or load","Only between the two outermost line conductors","Only at the neutral point","Only at the point of generation, never at the load"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Phase voltage/current specifically refers to the values associated with a single winding, as opposed to line quantities measured between line conductors." },
{ q:"'Line' quantities in a three-phase system refer to voltage/current measured:",
  opts:["Between or through the line conductors supplying the system","Only across a single phase winding","Only at the neutral point","Only inside the generator windings"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Line voltage/current is measured between the external line conductors that connect the source to the load." },
{ q:"A balanced star-connected load has a line voltage of 415 V. Find the voltage across each phase (winding) of the load.",
  opts:["≈239.6 V","415 V","≈718.9 V","≈207.5 V"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"VP = VL/√3 = 415/1.732 ≈ 239.6 V." },
{ q:"A balanced delta-connected load draws a line current of 20 A. Find the current through each phase (winding) of the load.",
  opts:["≈11.55 A","20 A","≈34.64 A","≈6.67 A"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"IP = IL/√3 = 20/1.732 ≈ 11.55 A." },
{ q:"A 'balanced' three-phase load is one in which:",
  opts:["All three phases have identical impedance, drawing equal currents 120° apart","Only two of the three phases carry current","Each phase has a different power factor","The neutral wire always carries maximum current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A balanced load ensures symmetric current draw across all three phases, maintaining zero neutral current in a star system." },
{ q:"The two-wattmeter method is commonly used to measure:",
  opts:["Total power in a three-phase, three-wire system (balanced or unbalanced), using just two wattmeters","Only reactive power in a single-phase circuit","Total power in a DC circuit only","Only the power factor of a purely resistive load"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"With just two wattmeters correctly connected, total three-phase power can be measured even without a neutral connection, for balanced or unbalanced loads." },
{ q:"In the two-wattmeter method, if both wattmeters show equal positive readings, the load power factor is:",
  opts:["Unity (1.0)","Zero","0.5 lagging","Impossible to determine"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"Equal wattmeter readings occur specifically at unity power factor (cosφ=1), a special case of the two-wattmeter method." },
{ q:"In the two-wattmeter method, the total reactive power (for a balanced load) can be calculated from the two readings W1 and W2 as:",
  opts:["Q = √3 × (W1 − W2)","Q = W1 + W2","Q = W1 × W2","Q = (W1 − W2)/√3"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"This relationship allows the reactive power to be derived from the same two wattmeter readings used to find total active power (P=W1+W2)." },
{ q:"Delta-connected loads are sometimes preferred over star connections in industrial applications because:",
  opts:["They can continue operating (at reduced capacity) even if one phase winding fails, unlike a star connection without neutral","They always require a neutral wire to function","They draw less current than an equivalent star connection","They cannot be used with three-phase motors"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"If one phase of a delta load opens, the remaining two phases can still supply power (in a degraded 'open-delta' mode), offering better fault tolerance than an ungrounded star." },
{ q:"The 'single-phase equivalent' method for analysing balanced three-phase circuits works by:",
  opts:["Analysing just one phase of an equivalent star-connected system, then extending results using 120° symmetry","Ignoring two of the three phases entirely, with no further calculation","Converting the entire system into a purely DC equivalent","Analysing only the neutral wire's behaviour"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Because of the inherent symmetry of a balanced three-phase system, solving just one phase (after converting delta loads to star) is sufficient to find results for all three phases." },
{ q:"A synchronous motor's field winding is typically excited by:",
  opts:["A DC supply, often through slip rings or a brushless exciter","An AC supply at the same frequency as the stator","A permanent magnet only, with no external supply","The same three-phase AC supply as the stator windings"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The rotor field winding of a synchronous machine requires a separate DC excitation source to establish its magnetic field." },
{ q:"A three-phase induction motor, unlike a synchronous motor, operates at a speed that is:",
  opts:["Always slightly less than synchronous speed, due to 'slip'","Always exactly equal to synchronous speed","Always greater than synchronous speed","Completely independent of the supply frequency"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"An induction motor relies on relative motion between the rotor and the rotating stator field to induce rotor current, so it must run slightly below synchronous speed." },
{ q:"'Slip' in an induction motor is defined as:",
  opts:["The difference between synchronous speed and actual rotor speed, as a fraction of synchronous speed","The difference between stator and rotor winding resistance","The angle between stator and rotor magnetic fields","The ratio of rotor current to stator current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Slip = (Ns − Nr)/Ns, quantifying how far the rotor lags behind the synchronously rotating stator field." },
{ q:"A three-phase induction motor has a synchronous speed of 1500 rpm and an actual rotor speed of 1450 rpm. Find the slip.",
  opts:["≈3.33%","5%","50%","≈1.03%"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"Slip = (Ns−Nr)/Ns = (1500−1450)/1500 = 50/1500 ≈ 3.33%." },
{ q:"The synchronous speed of a three-phase induction motor is given by:",
  opts:["Ns = 120f/P","Ns = f/P","Ns = 120P/f","Ns = P/(120f)"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Synchronous speed depends on supply frequency (f) and the number of poles (P) in the machine's winding." },
{ q:"Find the synchronous speed of a 4-pole, 50 Hz three-phase induction motor.",
  opts:["1500 rpm","3000 rpm","750 rpm","1000 rpm"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Ns = 120f/P = 120×50/4 = 1500 rpm." },
{ q:"At standstill (before starting), the slip of an induction motor is:",
  opts:["1 (100%), since rotor speed is zero","0 (0%), same as at synchronous speed","0.5 (50%), regardless of motor design","Undefined at standstill"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"With the rotor stationary (Nr=0), slip = (Ns−0)/Ns = 1, i.e., 100% slip at the moment of starting." },
{ q:"As the load on an induction motor increases, the slip generally:",
  opts:["Increases, as rotor speed decreases slightly to develop more torque","Decreases, as rotor speed increases to reduce torque","Remains exactly constant, regardless of load","Becomes negative"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Greater load demands more torque, which requires a larger relative speed difference (higher slip) between rotor and stator field to induce sufficient rotor current." },
{ q:"The main reason three-phase induction motors are widely used in industry is their:",
  opts:["Robust, brushless construction, self-starting capability, and low maintenance requirements","Requirement for a DC excitation supply, like synchronous motors","Very high cost compared to all other motor types","Inability to operate continuously under load"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Without brushes, slip rings, or a separate excitation supply, induction motors are simple, rugged, self-starting, and require minimal maintenance — ideal for industrial use." }
);

// ─────────────────────────────────────────────────────────
// TOPIC 1: ELECTRICAL MACHINES — Transformers (40Q)
// ─────────────────────────────────────────────────────────
QUESTION_BANK[1].push(
{ q:"A transformer works on the principle of:",
  opts:["Mutual induction, transferring energy between windings via a common magnetic flux","Self-induction only, with no coupling between windings","Mechanical rotation of a rotor within a magnetic field","Direct electrical conduction between primary and secondary"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"A transformer has no moving parts — it transfers electrical energy from primary to secondary purely through mutual induction via a shared magnetic flux." },
{ q:"A transformer does not work on DC supply because:",
  opts:["A constant DC flux produces no rate of change of flux, so no EMF is induced in the secondary","DC current is too small to establish any magnetic flux","Transformers can only handle three-phase supplies","DC voltage is always too high for transformer windings"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Faraday's Law requires a changing flux to induce EMF; a steady DC current (after the initial transient) produces constant flux, giving zero induced secondary EMF." },
{ q:"The EMF equation of a transformer is given by:",
  opts:["E = 4.44 f N Φm","E = 2 f N Φm","E = f N Φm / 4.44","E = 4.44 N / (f Φm)"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This standard formula relates induced EMF to supply frequency (f), number of turns (N), and maximum core flux (Φm)." },
{ q:"A transformer has 200 primary turns, operates at 50 Hz, with a maximum core flux of 0.02 Wb. Find the primary induced EMF.",
  opts:["888 V","444 V","1776 V","200 V"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"E = 4.44 × f × N × Φm = 4.44 × 50 × 200 × 0.02 = 888 V." },
{ q:"The turns ratio (a) of a transformer relates primary and secondary quantities as:",
  opts:["a = N1/N2 = V1/V2 = I2/I1","a = N1/N2 = V2/V1 = I1/I2","a = N2/N1 = V1/V2","a = N1×N2 = V1×V2"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Voltage ratio follows the turns ratio directly, while current ratio is inversely proportional, for an ideal transformer." },
{ q:"A transformer has 400 primary turns and 100 secondary turns, with a primary voltage of 230 V. Find the secondary voltage (assuming an ideal transformer).",
  opts:["57.5 V","920 V","230 V","115 V"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"V2 = V1 × (N2/N1) = 230 × (100/400) = 57.5 V." },
{ q:"In an ideal transformer, the relationship between primary current (I1) and secondary current (I2) is:",
  opts:["I1/I2 = N2/N1 (inversely proportional to turns ratio)","I1/I2 = N1/N2 (directly proportional to turns ratio)","I1 = I2, regardless of turns ratio","I1 × I2 = N1 × N2"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since an ideal transformer conserves power (V1I1=V2I2), current ratio is the inverse of the voltage (turns) ratio." },
{ q:"A transformer has a turns ratio N1:N2 = 4:1, and the secondary current is 20 A. Find the primary current (ideal transformer).",
  opts:["5 A","80 A","20 A","4 A"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"I1 = I2 × (N2/N1) = 20 × (1/4) = 5 A." },
{ q:"The two main types of losses in a transformer are:",
  opts:["Core (iron) losses and copper (I²R) losses","Only friction and windage losses","Only dielectric losses","Only stray load losses"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Unlike rotating machines, a transformer has no friction/windage losses — its main losses are core losses and copper losses." },
{ q:"Core (iron) losses in a transformer consist of:",
  opts:["Hysteresis loss and eddy current loss","Only copper (I²R) loss","Only friction loss","Only dielectric loss in the windings"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Both hysteresis and eddy current losses occur in the core due to the alternating flux, and are roughly constant regardless of load current." },
{ q:"Copper losses in a transformer vary with:",
  opts:["The square of the load current (I²R)","The supply frequency only","The core flux density only, not current","The transformer's physical weight"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since copper loss = I²R in the windings, it increases with the square of the load current, making it a 'variable loss' unlike the roughly constant iron loss." },
{ q:"Hysteresis loss in a transformer core is minimised by using:",
  opts:["Silicon steel (CRGO) laminations with a narrow hysteresis loop","Pure copper laminations","A solid (non-laminated) iron core","Aluminium core laminations"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"CRGO silicon steel has a narrow B-H loop, minimising the energy dissipated per magnetisation cycle." },
{ q:"Eddy current loss in a transformer core is minimised by:",
  opts:["Laminating the core with thin, insulated laminations","Using a thicker, solid core block","Increasing the operating frequency","Removing the core entirely"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Thin, insulated laminations increase the resistance path for circulating eddy currents, significantly reducing this loss component." },
{ q:"The condition for maximum efficiency of a transformer is:",
  opts:["Copper loss equals iron loss (variable loss = constant loss)","Copper loss is always zero","Iron loss is always zero","Copper loss is always double the iron loss"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Just like DC machines, transformer efficiency peaks when the load-dependent copper loss equals the constant iron loss." },
{ q:"A transformer has an iron loss of 200 W and a full-load copper loss of 800 W. At what fraction of full load will maximum efficiency occur?",
  opts:["50% of full load","25% of full load","75% of full load","100% of full load"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"At maximum efficiency, x²×Pcu(FL) = Piron, so x² = 200/800 = 0.25, giving x = 0.5, i.e. 50% of full load." },
{ q:"Voltage regulation of a transformer is defined as:",
  opts:["The change in secondary voltage from no-load to full-load, as a percentage of rated voltage","The ratio of primary to secondary voltage","The total power loss in the transformer","The efficiency of the transformer at full load"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Voltage regulation quantifies how much the secondary voltage sags (or rises) as load is applied, at a given power factor." },
{ q:"'All-day efficiency' of a transformer is defined as:",
  opts:["The ratio of total energy output to total energy input over a 24-hour period","The efficiency measured only at full load for one hour","The efficiency measured only at no-load","The average of morning and evening efficiency readings only"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Unlike ordinary power efficiency (measured at an instant), all-day efficiency accounts for energy (kWh) over a full day of varying load." },
{ q:"All-day efficiency is more relevant than ordinary efficiency specifically for:",
  opts:["Distribution transformers, which operate at varying/light loads for much of the day","Power transformers running continuously near full load","Autotransformers only","Transformers used exclusively in testing laboratories"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since distribution transformers see fluctuating, often light loads throughout the day, all-day efficiency better reflects their real energy performance than simple full-load efficiency." },
{ q:"The Open Circuit (OC) test on a transformer is performed to determine:",
  opts:["Core (iron) losses and no-load parameters","Copper losses at rated current","The transformer's voltage regulation directly","The transformer's physical weight and dimensions"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"With one side open-circuited and rated voltage applied to the other, the input power essentially represents the core loss, along with the no-load (magnetising) current." },
{ q:"The Short Circuit (SC) test on a transformer is performed to determine:",
  opts:["Copper losses at rated current and equivalent series impedance","Core (iron) losses at rated voltage","The transformer's no-load current only","The transformer's all-day efficiency directly"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"With one side short-circuited and just enough reduced voltage applied to circulate rated current, the input power essentially represents the copper loss at that current." },
{ q:"In the OC test, the transformer is set up with:",
  opts:["The secondary (or LV side) left open-circuited, rated voltage applied to the primary","The secondary short-circuited, reduced voltage applied to the primary","Both sides short-circuited simultaneously","Both sides left open, with no voltage applied"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The open-circuit condition on the secondary allows only the small no-load/magnetising current to flow, isolating the core loss measurement." },
{ q:"In the SC test, the transformer is set up with:",
  opts:["The secondary short-circuited, with reduced voltage applied just enough to circulate rated current","The secondary left open, with full rated voltage applied","Both windings disconnected from the supply entirely","The primary short-circuited and secondary supplied at full voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since the winding impedance is low, only a small applied voltage is needed to drive rated current through the short-circuited secondary, keeping core loss negligible during this test." },
{ q:"An autotransformer differs from a two-winding transformer in that it:",
  opts:["Uses a single winding common to both primary and secondary, providing electrical connection between the two sides","Uses two completely separate cores","Cannot be used to step up voltage, only step down","Requires a DC supply to operate"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"An autotransformer's primary and secondary share part of the same winding, unlike a conventional transformer's fully isolated windings." },
{ q:"The main advantage of an autotransformer over a two-winding transformer, for the same power rating, is:",
  opts:["Reduced size, weight, cost, and losses due to the shared winding","Complete electrical isolation between primary and secondary","Higher cost but better efficiency in all cases","Ability to operate on DC supply"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Because part of the winding (and its copper) is shared between primary and secondary, an autotransformer is generally smaller, lighter, and more efficient for the same rating." },
{ q:"The main disadvantage of an autotransformer compared to a two-winding transformer is:",
  opts:["Lack of electrical isolation between primary and secondary","Much larger physical size","Inability to step up voltage","Requirement for external cooling in all cases"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since the windings are electrically connected (not just magnetically coupled), a fault on one side can directly affect the other — a safety consideration in some applications." },
{ q:"In three-phase transformers, the 'Delta-Star' connection is commonly used for:",
  opts:["Step-up transformers at generating stations","Step-down transformers at distribution substations only","Autotransformers exclusively","Single-phase transformers only"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A delta primary keeps line currents balanced even under some unbalance, while a star secondary conveniently provides a neutral point for further transmission." },
{ q:"In three-phase transformers, the 'Star-Delta' connection is commonly used for:",
  opts:["Step-down transformers at the receiving/distribution end","Step-up transformers only, never step-down","High-voltage transmission lines exclusively","DC transmission systems"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A star primary provides a neutral on the high-voltage side (useful for grounding), while the delta secondary suits distribution-level connections." },
{ q:"The 'vector group' of a transformer indicates:",
  opts:["The phase displacement between primary and secondary line voltages, along with winding connection type","Only the transformer's kVA rating","The transformer's cooling method only","The number of physical cores used"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Vector group notation (e.g., Dyn11) specifies both the winding connections (delta/star) and the standardised phase angle shift between primary and secondary." },
{ q:"For successful parallel operation of two transformers, one essential condition is that they must have:",
  opts:["The same voltage ratio (turns ratio)","Different voltage ratios, to balance loading","The same physical size and weight","Different vector groups for phase diversity"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Mismatched voltage ratios would cause a circulating current to flow between the parallel transformers even at no load." },
{ q:"Another essential condition for parallel operation of transformers is that they must have:",
  opts:["The same polarity (phase sequence/vector group)","Different manufacturers for redundancy","Equal physical dimensions","Different cooling methods"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Incorrect polarity/phase matching when paralleling transformers can effectively create a short-circuit condition upon connection." },
{ q:"Transformers intended for parallel operation should also ideally have:",
  opts:["Equal percentage impedance, to ensure proportional load sharing","Widely different percentage impedances for redundancy","No impedance at all","Equal no-load losses only, regardless of impedance"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Equal percentage impedance ensures each paralleled transformer shares the total load in proportion to its own kVA rating." },
{ q:"The Buchholz relay protects oil-immersed transformers by:",
  opts:["Detecting gas accumulation from developing faults and sudden oil surges from severe faults","Directly interrupting the primary current like a circuit breaker","Measuring the transformer's efficiency continuously","Regulating the transformer's output voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Mounted between the main tank and conservator, the Buchholz relay senses gas bubbles and oil surges characteristic of internal transformer faults." },
{ q:"The transformer cooling method 'ONAN' stands for:",
  opts:["Oil Natural, Air Natural","Oil Natural, Air Forced","Oil Forced, Air Natural","Oil Forced, Air Forced"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"ONAN relies purely on natural convection of oil and natural air circulation, with no pumps or fans — the simplest cooling method." },
{ q:"The transformer cooling method 'ONAF' stands for:",
  opts:["Oil Natural, Air Forced","Oil Natural, Air Natural","Oil Forced, Air Natural","Oil Forced, Air Forced"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"ONAF uses natural oil circulation combined with forced-air cooling (via fans) to improve heat dissipation over ONAN." },
{ q:"A 'step-up' transformer increases voltage from primary to secondary, meaning it has:",
  opts:["More turns on the secondary winding than the primary","Fewer turns on the secondary winding than the primary","Equal turns on both windings","No winding on the secondary side"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Since voltage is proportional to turns, a step-up transformer must have a higher secondary turn count than its primary." },
{ q:"A 'step-down' transformer decreases voltage from primary to secondary, meaning it has:",
  opts:["Fewer turns on the secondary winding than the primary","More turns on the secondary winding than the primary","Equal turns on both windings","No winding on the primary side"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"A step-down transformer reduces voltage, requiring fewer secondary turns relative to the primary." },
{ q:"The 'magnetising current' of a transformer is:",
  opts:["The small no-load current component that establishes the mutual core flux, lagging voltage by 90°","The full-load current under normal operating conditions","The current that flows only during a short-circuit fault","A current found only in autotransformers"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Magnetising current is a small reactive component of the no-load current, responsible for setting up the mutual flux in the transformer core." },
{ q:"In a transformer's equivalent circuit, the shunt (magnetising) branch represents:",
  opts:["Core loss (via a resistance) and magnetising reactance (via an inductive reactance), both in parallel","Only the winding resistance","Only the leakage reactance of the secondary","The load impedance connected to the secondary"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"The shunt branch models the no-load behaviour: a resistance accounting for core loss and a reactance accounting for magnetising current, both across the primary." },
{ q:"A 400/200 V single-phase transformer has a full-load secondary current of 50 A. Find the equivalent full-load primary current (ideal transformer).",
  opts:["25 A","50 A","100 A","12.5 A"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"By power balance, V1×I1 = V2×I2, so I1 = (V2×I2)/V1 = (200×50)/400 = 25 A." },
{ q:"The rating of a transformer is generally expressed in:",
  opts:["kVA (kilovolt-amperes)","kW (kilowatts) only","Amperes only","Volts only"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since transformer losses (mainly copper loss) depend on current rather than load power factor, ratings are given in kVA rather than kW." }
);

// ─────────────────────────────────────────────────────────
// TOPIC 1: ELECTRICAL MACHINES — AC Machines / Induction Motor (34Q)
// ─────────────────────────────────────────────────────────
QUESTION_BANK[1].push(
{ q:"A three-phase induction motor's rotating magnetic field is produced by:",
  opts:["Three-phase currents flowing through three stator windings spaced 120° apart","A single DC-excited rotor winding","Permanent magnets mounted on the stator","Mechanical rotation of brushes on a commutator"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The three-phase stator currents, offset both spatially (120°) and in time phase, combine to produce a smoothly rotating magnetic field with no moving parts required on the stator." },
{ q:"The speed of the rotating magnetic field (synchronous speed) in an induction motor is given by:",
  opts:["Ns = 120f/P","Ns = f/P","Ns = 120P/f","Ns = P/(120f)"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Synchronous speed depends directly on supply frequency (f) and inversely on the number of poles (P)." },
{ q:"An induction motor is also called an 'asynchronous motor' because:",
  opts:["It always runs at a speed different from (less than) synchronous speed","It cannot run continuously under load","It requires a DC supply to operate","It has no rotating magnetic field at all"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Unlike a synchronous motor, an induction motor's rotor speed never exactly equals synchronous speed under normal loaded operation — hence 'asynchronous'." },
{ q:"The two main types of three-phase induction motors, based on rotor construction, are:",
  opts:["Squirrel cage and slip-ring (wound rotor) types","Series and shunt types","Salient pole and cylindrical rotor types","Brushed and brushless types"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"These two rotor construction types define the two major categories of three-phase induction motors." },
{ q:"A squirrel cage induction motor's rotor consists of:",
  opts:["Copper or aluminium bars short-circuited by end rings","A wound winding identical to the stator, brought out via slip rings","Permanent magnets embedded in the rotor core","A DC-excited field winding"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"This simple, rugged 'cage' structure requires no external electrical connection to the rotor, making it low-maintenance." },
{ q:"A slip-ring (wound rotor) induction motor's rotor winding is:",
  opts:["Similar to the stator winding, with terminals brought out via slip rings for external resistance control","Made entirely of permanent magnets","A simple short-circuited cage, identical to a squirrel cage rotor","Excited by a separate DC supply, like a synchronous motor"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Slip rings allow external resistance to be added to the rotor circuit, enabling improved starting torque and speed control." },
{ q:"The main advantage of a squirrel cage induction motor over a slip-ring type is:",
  opts:["Simpler, more rugged construction with lower cost and less maintenance","Higher starting torque with lower starting current","Ability to control speed via external rotor resistance","Requirement for a separate DC excitation supply"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Without brushes or slip rings to maintain, squirrel cage motors are simpler, more robust, and cheaper — the most widely used industrial motor type." },
{ q:"The main advantage of a slip-ring induction motor over a squirrel cage type is:",
  opts:["Higher starting torque with lower starting current, via external rotor resistance","Lower initial cost","Simpler, brushless construction","Higher operating speed at all times"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Adding external resistance to the rotor circuit during starting improves torque while limiting the high inrush starting current typical of cage motors." },
{ q:"At starting (standstill), an induction motor's rotor frequency equals:",
  opts:["The supply (stator) frequency, since slip is 100%","Zero, regardless of supply frequency","Half the supply frequency","Twice the supply frequency"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"At standstill, slip = 1, so rotor frequency fr = s×f = 1×f = the full supply frequency." },
{ q:"As an induction motor speeds up from standstill, the rotor frequency:",
  opts:["Decreases, becoming equal to slip × supply frequency","Increases, exceeding the supply frequency","Remains constant, equal to the supply frequency","Becomes negative"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"As slip decreases with increasing rotor speed, rotor frequency (fr = s×f) proportionally decreases." },
{ q:"A 50 Hz induction motor operates with a slip of 4%. Find the rotor frequency.",
  opts:["2 Hz","4 Hz","50 Hz","0.5 Hz"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"fr = s × f = 0.04 × 50 = 2 Hz." },
{ q:"The starting current of a squirrel cage induction motor on direct-on-line (DOL) starting is typically:",
  opts:["Very high, roughly 5–7 times the full-load current","Lower than the full-load running current","Exactly equal to the full-load current","Independent of the motor's rating"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"At standstill, the rotor's induced EMF and impedance are such that current inrush is very high compared to normal running current." },
{ q:"A star-delta starter reduces induction motor starting current by:",
  opts:["Initially connecting stator windings in star (reducing per-phase voltage), then switching to delta for running","Increasing the supply frequency during starting","Adding external rotor resistance permanently","Disconnecting one phase during starting"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Starting in star reduces the voltage across each winding to 1/√3 of the line voltage, substantially cutting starting current before switching to delta for full-voltage running." },
{ q:"Using a star-delta starter, the starting line current (compared to direct delta starting) is reduced to approximately:",
  opts:["1/3 of the direct-on-line starting current","1/√3 of the direct-on-line starting current","2/3 of the direct-on-line starting current","The same as direct-on-line starting"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"The combined effect of reduced per-phase voltage and the star/delta configuration change reduces the starting line current to about one-third of direct starting." },
{ q:"An autotransformer starter reduces induction motor starting current and torque by:",
  opts:["Applying reduced voltage via transformer tapping during starting, then switching to full voltage","Permanently connecting the motor in star configuration","Adding a series capacitor to the stator circuit","Reversing two supply phases briefly"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"An autotransformer starter provides a selectable reduced-voltage tap for starting, then transitions the motor to full supply voltage for normal running." },
{ q:"A Direct-On-Line (DOL) starter is most suitable for:",
  opts:["Small induction motors, where high starting current doesn't significantly disturb the supply","Very large induction motors on weak supply networks","Motors requiring precise speed control during starting","Motors that must never draw more than rated current"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"For small motors, the brief high starting current inrush is generally tolerable for the supply system, making DOL starting simple and cost-effective." },
{ q:"The torque developed by an induction motor is generally proportional to:",
  opts:["The square of the applied stator voltage (T ∝ V²)","The applied stator voltage directly (T ∝ V)","The square root of the applied stator voltage","The inverse of the applied stator voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since torque depends on the square of the induced rotor EMF/current (both proportional to stator voltage), torque is proportional to V²." },
{ q:"If the supply voltage to an induction motor drops significantly, its starting/running torque:",
  opts:["Decreases sharply, since torque ∝ V²","Increases sharply","Remains completely unaffected","Becomes negative, reversing the motor"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Because torque is proportional to the square of voltage, even a modest voltage drop causes a much larger proportional torque reduction, risking stalling under load." },
{ q:"The torque-slip characteristic of an induction motor shows torque increasing with slip up to a maximum point called:",
  opts:["The 'pull-out' or 'breakdown' torque","The 'starting' torque only","The 'synchronous' torque","The 'no-load' torque"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Beyond this maximum (breakdown) torque point, further increases in slip actually cause torque to decrease." },
{ q:"Operating an induction motor beyond its breakdown (pull-out) torque point causes it to:",
  opts:["Stall, rapidly losing speed and stopping","Accelerate rapidly to a higher speed","Continue running smoothly at reduced efficiency","Switch automatically to generator mode"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Since torque decreases with further slip increase beyond breakdown, the motor cannot sustain the load and stalls." },
{ q:"The 'crawling' phenomenon in a squirrel cage induction motor refers to:",
  opts:["The motor stably running at a much lower speed than normal, due to air-gap flux harmonics","The motor refusing to start at all due to magnetic locking","Excessive vibration during normal full-speed running","A sudden reversal of rotation direction"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"Harmonic components in the air-gap flux (commonly the 7th harmonic) can create a stable, much slower rotating field, causing the motor to 'crawl' at around 1/7th synchronous speed instead of accelerating normally." },
{ q:"The 'cogging' (magnetic locking) phenomenon in an induction motor refers to:",
  opts:["The motor's refusal to start at all, due to stator/rotor slot harmonic alignment","The motor running at exactly synchronous speed","A gradual increase in motor efficiency over time","The motor overheating during normal operation"], ans:0, level:"Hard", tag:"🟢 CONCEPT",
  exp:"When stator and rotor slot numbers create a strong harmonic locking torque at standstill, the motor can fail to start, remaining magnetically 'stuck'." },
{ q:"Cogging in induction motors is typically avoided by:",
  opts:["Skewing the rotor slots at a slight angle relative to the shaft axis","Increasing the number of stator poles significantly","Removing the rotor bars entirely","Operating the motor only at reduced voltage"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Skewed rotor slots smooth out the harmonic interactions between stator and rotor slotting, preventing the strong magnetic locking that causes cogging." },
{ q:"The rotor of an induction motor rotates in:",
  opts:["The same direction as the stator's rotating magnetic field, always slightly behind it","The opposite direction to the stator's rotating field","A direction independent of the stator field","A direction that reverses every half cycle"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The rotor is dragged along by the rotating stator field but always lags behind it — this lag (slip) is what induces the rotor currents producing torque." },
{ q:"Speed control of an induction motor by varying supply frequency is achieved using:",
  opts:["A Variable Frequency Drive (VFD), which also varies voltage proportionally to maintain flux","A simple series resistor in the stator circuit only","A capacitor bank connected permanently across the motor terminals","Reversing the phase sequence continuously"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A VFD adjusts both frequency and voltage together (V/f control) to maintain constant flux while smoothly varying motor speed." },
{ q:"Speed control of a slip-ring induction motor via external rotor resistance:",
  opts:["Reduces motor speed (increases slip) for a given load torque, at the cost of reduced efficiency","Increases motor speed above synchronous speed","Has no effect on motor speed at all","Only works when the motor is unloaded"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Adding rotor resistance increases slip needed to develop the same torque, lowering speed — but the extra energy dissipated in the resistance reduces overall efficiency." },
{ q:"The 'no-load test' on an induction motor is used to determine:",
  opts:["Core losses, friction/windage losses, and the no-load magnetising current","Copper losses at rated current only","The motor's exact starting torque","The motor's breakdown torque directly"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Analogous to a transformer's OC test, the no-load test isolates the constant losses and magnetising current of the induction motor." },
{ q:"The 'blocked-rotor test' on an induction motor is used to determine:",
  opts:["Equivalent circuit impedance parameters and copper losses at (near) rated current","Only the motor's no-load speed","Only the motor's core loss","The motor's all-day efficiency"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Analogous to a transformer's SC test, the blocked-rotor test (rotor held stationary) reveals the motor's series impedance and copper losses near rated current." },
{ q:"A single-phase induction motor is not self-starting because:",
  opts:["A single-phase winding alone produces a pulsating, not rotating, magnetic field","It has no rotor at all","It requires a DC supply to start","Its stator winding is always short-circuited"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A pulsating field can be resolved into two opposite-rotating fields that produce zero net starting torque at standstill, so an auxiliary starting mechanism is required." },
{ q:"A capacitor-start induction motor achieves starting torque by:",
  opts:["Using an auxiliary winding with a series capacitor to create a phase difference, producing a rotating-field effect","Using a permanent magnet rotor for self-starting","Applying a much higher voltage only during starting","Reversing the main winding connections briefly"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"The capacitor introduces a phase shift between the main and auxiliary winding currents, approximating a two-phase rotating field sufficient to start the motor." },
{ q:"Once a single-phase induction motor reaches sufficient speed, the starting (auxiliary) winding is typically:",
  opts:["Disconnected via a centrifugal switch, since it's no longer needed","Permanently short-circuited to the main winding","Reconnected in series with the main winding","Used to reverse the motor's direction automatically"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"A centrifugal switch (or similar mechanism) disconnects the auxiliary winding once the motor is running, since the main winding alone can then sustain rotation." },
{ q:"The efficiency of an induction motor is generally defined as:",
  opts:["Mechanical output power divided by electrical input power","Electrical input power divided by mechanical output power","The ratio of starting torque to running torque","The ratio of rotor frequency to stator frequency"], ans:0, level:"Easy", tag:"🟢 CONCEPT",
  exp:"Like any motor, efficiency = Output/Input, expressed as a percentage, reflecting how much input electrical power is converted to useful mechanical output." },
{ q:"Find the synchronous speed of a 6-pole, 50 Hz three-phase induction motor.",
  opts:["1000 rpm","1500 rpm","3000 rpm","500 rpm"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Ns = 120f/P = 120×50/6 = 1000 rpm." },
{ q:"An induction motor with a synchronous speed of 1000 rpm operates with 5% slip. Find its actual rotor speed.",
  opts:["950 rpm","1050 rpm","1000 rpm","900 rpm"], ans:0, level:"Medium", tag:"🟢 CONCEPT",
  exp:"Nr = Ns(1−s) = 1000×(1−0.05) = 1000×0.95 = 950 rpm." }
);
